+import { describe, it, expect, beforeEach } from 'vitest';
+import { EventBus } from '../../src/events/event-bus.js';
+import { NotificationService, resetNotificationIdCounter } from '../../src/services/notification.service.js';
+import { PreferencesService } from '../../src/services/preferences.service.js';
+import { NotificationHistoryService, resetLogIdCounter } from '../../src/services/notification-history.service.js';
+import { NotificationLogRepository } from '../../src/repositories/notification-log.repository.js';
+import { EmailAdapter, InMemoryTransport } from '../../src/adapters/email.adapter.js';
+import { SmsAdapter, InMemorySmsTransport } from '../../src/adapters/sms.adapter.js';
+import { WebhookAdapter, InMemoryWebhookTransport } from '../../src/adapters/webhook.adapter.js';
+import { Database } from '../../src/utils/database.js';
+import type { OrderCreatedEvent, OrderStatusChangedEvent } from '../../src/events/event-types.js';
+
+/**
+ * Integration tests for the full notification pipeline:
+ * EventBus → NotificationService → Adapters → Preferences → History
+ */
+describe('Notification Pipeline Integration', () => {
+  let eventBus: EventBus;
+  let db: Database;
+  let notificationService: NotificationService;
+  let preferencesService: PreferencesService;
+  let historyService: NotificationHistoryService;
+  let logRepo: NotificationLogRepository;
+
+  let emailTransport: InMemoryTransport;
+  let emailAdapter: EmailAdapter;
+  let smsTransport: InMemorySmsTransport;
+  let smsAdapter: SmsAdapter;
+  let webhookTransport: InMemoryWebhookTransport;
+  let webhookAdapter: WebhookAdapter;
+
+  // Reusable test data
+  const testUser = {
+    id: 'user-1',
+    name: 'Alice',
+    email: 'alice@example.com',
+    role: 'member' as const,
+    createdAt: new Date('2025-01-01'),
+    updatedAt: new Date('2025-01-01'),
+  };
+
+  const testOrder = {
+    id: 'order-1',
+    userId: 'user-1',
+    items: [
+      { productId: 'p1', name: 'Widget', quantity: 2, unitPrice: 10 },
+      { productId: 'p2', name: 'Gadget', quantity: 1, unitPrice: 25 },
+    ],
+    total: 45,
+    status: 'pending' as const,
+    createdAt: new Date('2025-01-15'),
+    updatedAt: new Date('2025-01-15'),
+  };
+
+  function makeOrderCreatedEvent(overrides?: Partial<OrderCreatedEvent>): OrderCreatedEvent {
+    return {
+      type: 'order:created',
+      order: { ...testOrder },
+      user: { ...testUser },
+      timestamp: new Date(),
+      ...overrides,
+    };
+  }
+
+  function makeOrderStatusChangedEvent(
+    overrides?: Partial<OrderStatusChangedEvent>,
+  ): OrderStatusChangedEvent {
+    return {
+      type: 'order:status-changed',
+      order: { ...testOrder, status: 'confirmed' },
+      userEmail: 'alice@example.com',
+      previousStatus: 'pending',
+      newStatus: 'confirmed',
+      timestamp: new Date(),
+      ...overrides,
+    };
+  }
+
+  beforeEach(() => {
