+
+    // Set up adapters with in-memory transports
+    emailTransport = new InMemoryTransport();
+    emailAdapter = new EmailAdapter({ transport: emailTransport });
+
+    smsTransport = new InMemorySmsTransport();
+    smsAdapter = new SmsAdapter({ transport: smsTransport });
+
+    webhookTransport = new InMemoryWebhookTransport();
+    webhookAdapter = new WebhookAdapter({ transport: webhookTransport });
+
+    // Wire up the full pipeline
+    notificationService = new NotificationService(eventBus);
+    notificationService.setPreferencesService(preferencesService);
+    notificationService.registerAdapter(emailAdapter);
+    notificationService.registerAdapter(smsAdapter);
+    notificationService.registerAdapter(webhookAdapter);
+
+    // History service subscribes to notification:sent/failed events
+    historyService = new NotificationHistoryService(eventBus, logRepo);
+  });
+
+  describe('Email channel end-to-end', () => {
+    it('should deliver email notification and log to history when email is enabled', async () => {
+      // Email is enabled by default — just emit the event
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      // Verify email was sent through transport
+      const sentMails = emailTransport.getSentMails();
+      expect(sentMails).toHaveLength(1);
+      expect(sentMails[0]!.to).toBe('alice@example.com');
+      expect(sentMails[0]!.subject).toContain('Order Confirmation');
+
+      // Verify adapter tracked the delivery
+      expect(emailAdapter.getSentEmails()).toHaveLength(1);
+
+      // Verify notification was stored in the service
+      const notifications = notificationService.getNotifications();
+      expect(notifications).toHaveLength(1);
+      expect(notifications[0]!.channel).toBe('email');
+      expect(notifications[0]!.recipient).toBe('alice@example.com');
+
+      // Verify history was logged
+      const history = historyService.getHistoryForRecipient('alice@example.com');
+      expect(history).toHaveLength(1);
+      expect(history[0]!.status).toBe('sent');
+      expect(history[0]!.channel).toBe('email');
+      expect(history[0]!.type).toBe('order:confirmation');
+    });
+
+    it('should render correct email template for order status update', async () => {
+      await eventBus.emit(makeOrderStatusChangedEvent());
+
+      const sentMails = emailTransport.getSentMails();
+      expect(sentMails).toHaveLength(1);
+      expect(sentMails[0]!.subject).toContain('Order Update');
+      expect(sentMails[0]!.html).toContain('Order Status Update');
