+      const smsHistory = historyService.query({ channel: 'sms' });
+      expect(smsHistory).toHaveLength(1);
+      expect(smsHistory[0]!.status).toBe('sent');
+      expect(smsHistory[0]!.recipient).toBe('+15551234567');
+    });
+
+    it('should not send SMS when SMS is disabled', async () => {
