+
+    it('should not send email when frequency is none', async () => {
+      preferencesService.updateEmailPreferences('user-1', { frequency: 'none' });
+
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      expect(emailTransport.getSentMails()).toHaveLength(0);
+      expect(notificationService.getNotificationCount()).toBe(0);
+    });
+
+    it('should not send when user unsubscribes from the notification category', async () => {
+      // Unsubscribe from order category
+      preferencesService.updateEmailPreferences('user-1', {
+        subscribedCategories: ['user'],
+      });
+
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      expect(emailTransport.getSentMails()).toHaveLength(0);
+      expect(notificationService.getNotificationCount()).toBe(0);
+    });
+
+    it('should not send SMS when phone number is missing even if enabled', async () => {
+      // Enable SMS but no phone number
+      preferencesService.updateSmsPreferences('user-1', {
+        enabled: true,
+        // phoneNumber intentionally omitted — defaults to null
+      });
+
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      expect(smsTransport.getSentMessages()).toHaveLength(0);
+    });
+
+    it('should not send webhook when URL is missing even if enabled', async () => {
+      preferencesService.updateWebhookPreferences('user-1', {
+        enabled: true,
+        // url intentionally omitted — defaults to null
+      });
+
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      expect(webhookTransport.getSentWebhooks()).toHaveLength(0);
+    });
+
+    it('should selectively send only to enabled channels', async () => {
+      // Disable email, enable SMS
+      preferencesService.updateEmailPreferences('user-1', { enabled: false });
+      preferencesService.updateSmsPreferences('user-1', {
+        enabled: true,
+        phoneNumber: '+15551234567',
+      });
+
+      await eventBus.emit(makeOrderCreatedEvent());
+
+      // Email should not be sent
+      expect(emailTransport.getSentMails()).toHaveLength(0);
+
+      // SMS should be sent
+      expect(smsTransport.getSentMessages()).toHaveLength(1);
+
+      // Only SMS in history
+      expect(historyService.getLogCount()).toBe(1);
+      expect(historyService.query({ channel: 'sms' })).toHaveLength(1);
+      expect(historyService.query({ channel: 'email' })).toHaveLength(0);
+    });
+  });
+
+  describe('History and audit trail', () => {
+    it('should log notifications with correct metadata', async () => {
